import json
import base64
import os

payloads = {
    "arkhe_v10_1_noesis.py": "",
    "substrate.toml": ""
}

def canonize():
    report = {
        "substrate_id": "1105",
        "name": "CathedralUI (NOESIS)",
        "status": "CANONIZED_FULL",
        "seal": "CATHEDRAL-ARKHE-v10.1.0-NOESIS-2026-06-15",
        "Files": {}
    }
    for file_path, content in payloads.items():
        report["Files"][file_path] = base64.b64decode(content).decode("utf-8")
    return json.dumps(report, indent=2)

if __name__ == "__main__":
    print(canonize())
